<span class="line"><span style="color:#F38BA8;">        self</span><span style="color:#94E2D5;">.</span><span style="color:#CDD6F4;">offset </span><span style="color:#94E2D5;">=</span><span style="color:#F38BA8;"> self</span><span style="color:#94E2D5;">.</span><span style="color:#CDD6F4;">offset</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">saturating_sub</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">lines</span><span style="color:#9399B2;">);</span></span>
